const apiKey = 'sk-nU7RSKnbZIOwH607r3MfbW5HmP6NIaj1aGVPFGcNDDiL0h5u';
const model = 'gemini-1.5-pro';
const url = 'https://ai.juguang.chat/v1/chat/completions';
const ctx = String($input.first().json.conversation_context || '').trim();

if (!ctx) {
  return [{ json: { choices: [{ message: { content: '{"ocean_disc":{"O":0,"C":0,"E":0,"A":0,"N":0}}' } }] } }];
}

const headers = {
  'Authorization': `Bearer ${apiKey}`,
  'Content-Type': 'application/json'
};

const body = {
  model: model,
  messages: [
    {
      role: 'system',
      content: 'You are a personality detector. Infer Big Five from the user text for THIS TURN ONLY. Return JSON ONLY exactly as: {"ocean_disc":{"O":-1|0|1,"C":-1|0|1,"E":-1|0|1,"A":-1|0|1,"N":-1|0|1}} No prose.'
    },
    {
      role: 'user',
      content: `Text: ${ctx}`
    }
  ],
  temperature: 0.1,
  max_tokens: 200
};

try {
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: url,
    headers: headers,
    body: body,
    timeout: 20000
  });
  return [{ json: res.json || res }];
} catch (error) {
  return [{ json: { choices: [{ message: { content: '{"ocean_disc":{"O":0,"C":0,"E":0,"A":0,"N":0}}' } }], error: error.message } }];
}

// Get the detection result from Detect OCEAN node
const det = $input.first()?.json || {};
const raw = det?.choices?.[0]?.message?.content ?? '';

// Get the session data from the previous workflow execution items
const ingestData = $items('Ingest (Per-turn, no smoothing)', 'main', 0)?.json || {};

// Debug: Check all available items
console.log('Parse Detection - All available items:', JSON.stringify($items()));
console.log('Parse Detection - Ingest items specifically:', JSON.stringify($items('Ingest (Per-turn, no smoothing)')));

console.log('Parse Detection - Detection result:', JSON.stringify(det));
console.log('Parse Detection - Ingest data:', JSON.stringify(ingestData));
console.log('Parse Detection - Raw API response content:', raw);

let parsed = {};
try {
  // First try to parse the raw content directly
  parsed = JSON.parse(raw);
} catch (e) {
  // If that fails, try to extract JSON from the content
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      parsed = JSON.parse(jsonMatch[0]);
    } catch (e2) {
      console.log('Failed to parse extracted JSON:', e2.message);
      parsed = {};
    }
  } else {
    console.log('No JSON found in content:', raw);
  }
}

console.log('Parse Detection - Parsed object:', JSON.stringify(parsed));

// Extract OCEAN discrete values
let oceanDisc = parsed?.ocean_disc;

// If ocean_disc doesn't exist but ocean does, convert continuous to discrete
if (!oceanDisc && parsed?.ocean) {
  const thr = 0.2;
  const o = parsed.ocean;
  const sign = (v) => (v >= thr ? 1 : (v <= -thr ? -1 : 0));
  oceanDisc = {
    O: sign(o.O || 0),
    C: sign(o.C || 0), 
    E: sign(o.E || 0),
    A: sign(o.A || 0),
    N: sign(o.N || 0)
  };
}

// Ensure we have a valid oceanDisc object
const od = oceanDisc || { O: 0, C: 0, E: 0, A: 0, N: 0 };

// Extract session data from ingest
const turnText = ingestData?.clean_msg || '';
const sessionId = ingestData?.session_id || '';

console.log('Parse Detection - Final ocean_disc values:', JSON.stringify(od));
console.log('Parse Detection - Session ID:', sessionId);
console.log('Parse Detection - Turn text:', turnText);

return [{
  json: {
    ocean_disc: od,
    turn_text: turnText,
    session_id: sessionId
  }
}];

