// Use directives to generate a grounded reply (hard-coded key)
const JUGUANG_API_KEY = 'sk-nU7RSKnbZIOwH607r3MfbW5HmP6NIaj1aGVPFGcNDDiL0h5u';
const MODEL = 'gemini-1.5-pro';
const URL = 'https://ai.juguang.chat/v1/chat/completions';

// Extract all data from the regulation input
const inputData = $input.first()?.json || {};
const directives = inputData?.directives || [];
const sessionId = inputData?.session_id || '';
const turnText = inputData?.turn_text || '';
const oceanDisc = inputData?.ocean_disc || { O:0, C:0, E:0, A:0, N:0 };

console.log('Generate Response - Input data:', JSON.stringify(inputData));
console.log('Generate Response - Ocean disc:', JSON.stringify(oceanDisc));
console.log('Generate Response - Session ID:', sessionId);
console.log('Generate Response - Turn text:', turnText);

let userText = turnText.trim();
if (!userText) {
  // Ensure content is not empty to satisfy backend validation
  userText = 'Please provide a supportive, grounded reply to the user. Context provided separately.';
}

const headers = {
  Authorization: `Bearer ${JUGUANG_API_KEY}`,
  'Content-Type': 'application/json'
};
const sys = [
  'You are a supportive assistant. Follow these behavior directives strictly:',
  JSON.stringify(directives),
  'Constraints: stay grounded in the user text only; 1-2 questions max; 70-150 words.'
].join(' ');

const body = {
  model: MODEL,
  messages: [
    { role: 'system', content: sys },
    { role: 'user', content: userText }
  ],
  temperature: 0.7,
  max_tokens: 220
};

try {
  const res = await this.helpers.httpRequest({ method: 'POST', url: URL, headers, body, timeout: 20000 });

  console.log('Generate Response - Raw API response:', JSON.stringify(res));
  console.log('Generate Response - API response json:', JSON.stringify(res.json));

  // Handle different response structures
  const apiResponse = res.json || res || {};

  const responseData = {
    // Preserve all API response fields first
    ...apiResponse,
    // Then add our session data (will override if conflicts)
    session_id: sessionId,
    turn_text: turnText,
    ocean_disc: oceanDisc,
    directives: directives
  };

  console.log('Generate Response - Final response data:', JSON.stringify(responseData));

  // Include session data in the response while preserving full API response
  return {
    json: responseData
  };
} catch (e) {
  const status = e?.response?.status;
  const data = e?.response?.data;

  // Fallback text with session data included
  return {
    json: {
      choices: [{ message: { content: 'Sorry—response is temporarily unavailable. Quick tip: take 3 slow breaths and exhale longer than you inhale.' } }],
      error: { status, data },
      session_id: sessionId,
      turn_text: turnText,
      ocean_disc: oceanDisc,
      directives: directives
    }
  };
}

